/**
 * Loader + types for the captured architecture-comparison benchmark report.
 *
 * The JSON is **real evidence**, generated by `scripts/build_benchmark_report.py`
 * from `benchmark/person_c_scorer.py` (typed path, scored live against the 30-case
 * gold suite) and, when present, the committed LLM-baseline reports. It is NOT a
 * fixture — it is the recorded output of a real scoring run. Architectures whose
 * report has not been produced are `status: "not_run"` (never fabricated).
 *
 * Regenerate: `python scripts/build_benchmark_report.py`.
 */

import reportJson from "./architecture-comparison.json";

export interface MeasuredArchitecture {
  key: string;
  label: string;
  status: "measured";
  caseCount: number;
  accuracyRate: number;
  accuracyPassed: number;
  accuracyTotal: number;
  hallucinationCount: number;
  hallucinationRate: number;
  invalidationRate: number;
  invalidationPassed: number;
  invalidationTotal: number;
  /** Real total token cost — null until `agent_runs.token_count` instrumentation is live. */
  tokenCostTotal: number | null;
}

export interface NotRunArchitecture {
  key: string;
  label: string;
  status: "not_run";
  /** Exact command that produces this architecture's report. */
  run: string;
}

export type ReportArchitecture = MeasuredArchitecture | NotRunArchitecture;

export interface BenchmarkReport {
  generatedAt: string;
  benchmarkId: string;
  fixtureId: string;
  evaluatorVersion: string;
  caseCount: number;
  note: string;
  architectures: ReportArchitecture[];
}

export const benchmarkReport = reportJson as unknown as BenchmarkReport;

export function isMeasured(a: ReportArchitecture): a is MeasuredArchitecture {
  return a.status === "measured";
}

/** Whole-percent label from a 0..1 rate, e.g. 1.0 → "100%". */
export function pct(rate: number): string {
  return `${Math.round(rate * 100)}%`;
}
